#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 2.5e7+5;
LL n,p[N],Ans;string t,s;
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
bool Yes(int x,int y){
    if(s[x]==s[y]&&s[x]=='#')return 1;
    else if(s[x]!=s[y])return 1;else return 0;
}
int main(){
    n=read();cin>>t;s=" ";
    for(char c:t)s+=c,s+='#';
    s.pop_back();n=s.size()-1;
    for(LL i=1,l=0,r=-1;i<=n;i++){
        LL len=(i>r?0:min(p[l+r-i],r-i+1));
        while(i-len>=1&&i+len<=n&&Yes(i-len,i+len))len++;
        p[i]=len;
        if(s[i]=='#')Ans+=len-(s[i+len-1]=='#');
        if(i+len-1>r)l=i-len+1,r=i+len-1;
    }cout<<Ans/2<<"\n";
    return 0;
}
